draw(U--(W + U)--(U + V + W));
draw((W + U)--W);
draw((V + U)--V--(V + W),dashed);
draw(O--V,dashed,Arrow3(6));
draw(O--W,Arrow3(6));
draw(O--U,Arrow3(6));

label("$x$", -3.2*I);
